sql:
SELECT SUM(total_cost) AS total_material_cost
FROM estimate_materials
WHERE estimate_id = 0;

SELECT SUM(al.quantity * l.rate) AS total_labor_cost
FROM activity_labor al
JOIN labor l ON al.labor_id = l.labor_id;

external_knowledge:
- Combined cost refers to the sum of the activity's total cost and its total estimated cost; 
- The query assumes that the costs are in the same currency units; 
- 'Active' projects are those with a status of 'active' and activities that are not 'completed'.

sql:
SELECT SUM(quantity) AS total_labor_quantity
FROM activity_labor
WHERE activity_id = 1;

SELECT labor_name, rate
FROM labor
WHERE department = 'Construction';

SELECT SUM(quantity) AS total_quantity_used
FROM estimate_materials
WHERE material_id = (SELECT material_id FROM materials WHERE material_name = 'Stone');

external_knowledge:
- 'ships that are still sailing' refers to 'active projects';
- 'helmsmen' are 'project managers';
- 'charted costly courses' refers to 'prepared estimates for activities with a total estimated cost exceeding $100,000'.

sql:
SELECT activity_id, estimate_date, total_cost
FROM cost_estimates
ORDER BY total_cost DESC;
